INSERT INTO users (name) VALUES ('TrendSee Demo');
INSERT INTO publications (user_id, title, text, cover_asset, created_at, updated_at) VALUES
(1, 'SPF скатывается катышками? 3 причины, о которых не говорят в рекламе', E'Показываю три типичных сценария: перебор ухода под SPF, несовместимые текстуры и перетирание салфеткой. В конце — короткий чеклист перед выходом. Без обещаний «идеальной кожи за неделю».\n\n#spf #уход #реальность', 'card_thumb_girl.png', NOW() - (120 * INTERVAL '1 hour'), NOW() - (120 * INTERVAL '1 hour')),
(1, 'Почему Reels залипает на 300 просмотров — чеклист за 45 секунд', E'Разбираю обложку, первые слова и плотность смысла в 15 секундах. Если хоть один пункт проседает — алгоритм реже отдаёт холодную аудиторию. Сохраняй, чтобы не потерять.\n\n#reels #контент', 'card_thumb_man.png', NOW() - (116 * INTERVAL '1 hour'), NOW() - (116 * INTERVAL '1 hour')),
(1, 'Зарплата в IT: ожидание vs реальность (честно, без сахара)', E'Сравниваю вилку зарплат по вакансиям и что реально выходит после налогов и рынка. Это не мотивация — цифры и личный опыт собесов за квартал.\n\n#it #карьера', 'card_thumb_tops.png', NOW() - (112 * INTERVAL '1 hour'), NOW() - (112 * INTERVAL '1 hour')),
(1, 'Как снять лицо на телефон без «мыла»: белая стена и один источник света', E'Снимаю в той же комнате: меняю только угол и расстояние до окна. Никакого софта «красоты» — только экспозиция и фокус. Подойдёт любому телефону с ручным режимом.\n\n#съёмка #iphone', 'card_thumb_text.png', NOW() - (108 * INTERVAL '1 hour'), NOW() - (108 * INTERVAL '1 hour')),
(1, 'Тинт + маска: держится 8 часов. Показываю наслоение по слоям', E'Сначала увлажнение, потом тинт, потом маска — показываю тайминг и где чаще всего «плывёт». Если спешишь с фиксацией, границы будут полосами.\n\n#макияж #быстро', 'card_thumb_1.png', NOW() - (104 * INTERVAL '1 hour'), NOW() - (104 * INTERVAL '1 hour')),
(1, 'Мой путь: кухонный стол → первые клиенты. Бизнес-история за 90 сек', E'Коротко про продукт, первые продажи и ту одну вещь, которую сделал бы на месяц раньше. Не лекция — просто честный срез, если думаешь стартовать.\n\n#бизнес #история', 'card_thumb_2.png', NOW() - (100 * INTERVAL '1 hour'), NOW() - (100 * INTERVAL '1 hour')),
(1, 'Три фразы на собесе, которые я бы убрал из резюме', E'Эти формулировки звучат уверенно на бумаге, но на скрининге часто режут доверие. Объясняю, что сказать вместо них — без воды.\n\n#собес #резюме', 'card_thumb_3.png', NOW() - (96 * INTERVAL '1 hour'), NOW() - (96 * INTERVAL '1 hour')),
(1, 'Трендовый звук + простой монтаж: удержание без «киношной» съёмки', E'Тренд из ленты + три кадра: лицо, руки, продукт. Монтаж в CapCut за 12 минут. Показываю темп и где ставить удар по биту.\n\n#монтаж #тренд', 'card_thumb_4.png', NOW() - (92 * INTERVAL '1 hour'), NOW() - (92 * INTERVAL '1 hour')),
(1, 'Первый кадр: три ошибки из-за которых листают дальше', E'Темный первый кадр, мелкий текст и долгое «привет» — три причины свайпа. Пара быстрых фиксов без пересъёмки.\n\n#хуки #reels', 'card_container.png', NOW() - (88 * INTERVAL '1 hour'), NOW() - (88 * INTERVAL '1 hour')),
(1, 'Контент-план на неделю без выгорания — мой Notion vs календарь', E'Пять слотов в неделю: два «лёгких», два «средних», один «длинный». Так меньше стыда за пропуски и больше завершённых роликов.\n\n#контентплан #рутина', 'video_thumb.jpg', NOW() - (84 * INTERVAL '1 hour'), NOW() - (84 * INTERVAL '1 hour')),
(1, 'Хук «одна из них пустышка» — почему работает на коротком видео', E'Вопрос без ответа в начале цепляет лучше плоского обещания. Показываю два варианта интонации — один из них провалился в тесте.\n\n#хук #удержание', 'video_card.png', NOW() - (80 * INTERVAL '1 hour'), NOW() - (80 * INTERVAL '1 hour')),
(1, 'B-roll по 0,4 сек: когда зритель «верит», что ты реально тестировал', E'Вставки по полсекунды дают ощущение «я правда щупал продукт». Главное — не превращать это в кашу из 20 переходов подряд.\n\n#монтаж #broll', 'search_results_page.png', NOW() - (76 * INTERVAL '1 hour'), NOW() - (76 * INTERVAL '1 hour')),
(1, 'CTA в комменты vs в профиль — что дало больше лидов в тесте', E'Один и тот же оффер: в комменты и «ссылка в шапке». Разница по заявкам оказалась заметной — цифры в конце ролика.\n\n#cta #маркетинг', 'video_detail_page.png', NOW() - (72 * INTERVAL '1 hour'), NOW() - (72 * INTERVAL '1 hour')),
(1, 'Монтаж: смена плана каждые 1,5 сек — формула удержания без звука', E'Лицо → объект → руки → лицо. Четыре якоря на 6 секунд — зритель не успевает выключить звук.\n\n#монтаж #ритм', 'card_thumb_girl.png', NOW() - (68 * INTERVAL '1 hour'), NOW() - (68 * INTERVAL '1 hour')),
(1, '«Я не продаю этот бренд» — триггер доверия в первых 3 секундах', E'Фраза снимает ощущение «мне впаривают», если ты реально не партнёришь бренд. Работает на отзывчивость в первых секундах.\n\n#доверие #ugc', 'card_thumb_man.png', NOW() - (64 * INTERVAL '1 hour'), NOW() - (64 * INTERVAL '1 hour')),
(1, 'Вилка выбора: жирная кожа / сухая — две ветки в одном ролике', E'Две дорожки в одном видео без путаницы: чёткое «если у тебя А — смотри сюда, если Б — досмотри до метки». Меньше отвалов по середине.\n\n#структура #ретеншн', 'card_thumb_tops.png', NOW() - (60 * INTERVAL '1 hour'), NOW() - (60 * INTERVAL '1 hour')),
(1, 'Что снимал на iPhone 14 vs камера: честное сравнение для Reels', E'Один и тот же свет и сцена — только камера. iPhone даёт достаточно для вертикали, если не злоупотреблять зумом и держать ISO.\n\n#iphone #камера', 'card_thumb_text.png', NOW() - (56 * INTERVAL '1 hour'), NOW() - (56 * INTERVAL '1 hour')),
(1, 'Ошибка в подборе музыки: три трека, которые убили охваты', E'Три трека из библиотеки: один дал охваты, два «убили» удержание из-за длинного интро. Коротко показываю волну формы звука.\n\n#звук #тренды', 'card_thumb_1.png', NOW() - (52 * INTERVAL '1 hour'), NOW() - (52 * INTERVAL '1 hour')),
(1, 'Как читают ленту HR-ы: первые 5 секунд твоего видео-отклика', E'Рекрутеры реально проматывают первые секунды. Называю роль, стек и результат в одном дыхании — без «здравствуйте, меня зовут» в начале.\n\n#собес #видеоотклик', 'card_thumb_2.png', NOW() - (48 * INTERVAL '1 hour'), NOW() - (48 * INTERVAL '1 hour')),
(1, 'Субтитры крупно или мелко — тест на одной и той же нарезке', E'Крупные субтитры выиграли у мелких на удержании в тихих местах. В шумном метро — наоборот. Разница в графике в конце.\n\n#субтитры #abтест', 'card_thumb_3.png', NOW() - (44 * INTERVAL '1 hour'), NOW() - (44 * INTERVAL '1 hour')),
(1, 'День из жизни продакта: встречи, задачи, один инсайт в конце', E'Смешал реальные встречи и одну мысль про приоритеты. Без «красивого офиса» — рутина, которая ближе большинству.\n\n#продукт #день', 'card_thumb_4.png', NOW() - (40 * INTERVAL '1 hour'), NOW() - (40 * INTERVAL '1 hour')),
(1, 'Разбор монтажа клипа: где зритель теряет интерес (таймкоды)', E'Разметил, где зритель делает паузу и где свайпает. Полезно, если монтируешь разборы чужих роликов или свои повторы.\n\n#разбор #монтаж', 'card_container.png', NOW() - (36 * INTERVAL '1 hour'), NOW() - (36 * INTERVAL '1 hour')),
(1, 'Кофе без сахара и понедельник — мини-ритуал перед съёмкой', E'Мелочь, но настраивает на съёмку: один ритуал до записи снижает количество «морально не готов».\n\n#рутина #съёмка', 'video_thumb.jpg', NOW() - (32 * INTERVAL '1 hour'), NOW() - (32 * INTERVAL '1 hour')),
(1, 'Репосты выросли в 2 раза после смены обложки — до/после', E'До: общий кадр из библиотеки. После: лицо крупно + контраст. CTR на превью вырос заметнее, чем я ожидал.\n\n#обложка #ctr', 'video_card.png', NOW() - (28 * INTERVAL '1 hour'), NOW() - (28 * INTERVAL '1 hour')),
(1, 'Как не утонуть в идеях: один столбец «снять на этой неделе»', E'Один столбец в таск-трекере + дедлайн «опубликовать или удалить». Меньше бесконечных черновиков.\n\n#идеи #дисциплина', 'search_results_page.png', NOW() - (24 * INTERVAL '1 hour'), NOW() - (24 * INTERVAL '1 hour')),
(1, 'Три вопроса к заказчику перед съёмкой UGC', E'Бюджет, сроки, права на материалы — три вопроса, которые экономят переделки. Текст на экране, можно ставить на паузу.\n\n#бриф #клиент', 'video_detail_page.png', NOW() - (20 * INTERVAL '1 hour'), NOW() - (20 * INTERVAL '1 hour')),
(1, 'Почему «обучающий» формат залетает сильнее «мотивации»', E'Обучение с конкретными шагами сохраняют чаще, чем абстрактная «мотивация». Показываю два примера из своей ленты.\n\n#формат #контент', 'card_thumb_girl.png', NOW() - (16 * INTERVAL '1 hour'), NOW() - (16 * INTERVAL '1 hour')),
(1, 'Скорость речи: замерил WPM и совпал с удержанием графика', E'Замерил скорость речи и совместил с пиками удержания на графике. Не догма, но ориентир есть.\n\n#речь #аналитика', 'card_thumb_man.png', NOW() - (12 * INTERVAL '1 hour'), NOW() - (12 * INTERVAL '1 hour')),
(1, 'Свет из окна + отражатель за 300₽ — разница в коже на камере', E'Мягкий свет из окна + отражатель из фойла и картона. Кожа читается без «пластика» — до/после в одном кадре.\n\n#свет #съёмка', 'card_thumb_tops.png', NOW() - (8 * INTERVAL '1 hour'), NOW() - (8 * INTERVAL '1 hour')),
(1, 'Итог месяца: 12 роликов, что сработало и что выкинул бы', E'Сводка: что окупило время, что было фоном и что не повторю в следующем месяце. Если нужен разбор одного пункта — напиши в комментах.\n\n#итоги #рост', 'card_thumb_text.png', NOW() - (4 * INTERVAL '1 hour'), NOW() - (4 * INTERVAL '1 hour'));
